// client/src/pages/LoginPage.jsx
import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import './AuthPage.css'; // Shared CSS for auth pages

const LoginPage = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [message, setMessage] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        setMessage('');

        // Placeholder for API call
        try {
            // In a real app, you'd send a POST request to your backend /api/auth/login
            // const response = await fetch('/api/auth/login', {
            //     method: 'POST',
            //     headers: { 'Content-Type': 'application/json' },
            //     body: JSON.stringify({ email, password })
            // });
            // const data = await response.json();

            // if (!response.ok) {
            //     throw new Error(data.message || 'Login failed');
            // }

            // Assuming successful login for now
            setMessage('Login successful! Redirecting...');
            console.log('Login successful for:', email);
            // Store token (e.g., localStorage.setItem('token', data.token))
            // Redirect user (e.g., navigate('/'))
        } catch (err) {
            setError(err.message || 'An error occurred during login.');
        }
    };

    return (
        <div className="auth-page container">
            <div className="auth-card card">
                <h2>Login to My Electroo</h2>
                {error && <p className="error-message">{error}</p>}
                {message && <p className="success-message">{message}</p>}
                <form onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label htmlFor="email">Email Address</label>
                        <input
                            type="email"
                            id="email"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                        />
                    </div>
                    <div className="form-group">
                        <label htmlFor="password">Password</label>
                        <input
                            type="password"
                            id="password"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                        />
                    </div>
                    <button type="submit" className="btn btn-primary auth-btn">Login</button>
                </form>
                <p className="auth-link-text">
                    Don't have an account? <Link to="/register">Register here</Link>
                </p>
            </div>
        </div>
    );
};

export default LoginPage;
